mapper.merge:

MERGE INTO	TBL_KKOMI tk USING (
SELECT #{User_No} AS user_no FROM DUAL
) src ON (tk.user_no = src.user_no)
WHEN NOT MATCHED THEN
	INSERT (User_No, kkomi_Id, kkomi_Lev, kkomi_exp)
	VALUES (src.User_No, 1, #{kkomiLev}, #{kkomiExp})
WHEN MATCHED THEN
	UPDATE SET tk.kkomi_Lev = #{kkomiLev}, tk.kkomi_Exp = #{kkomiExp}
	WHERE NVL(tk.kkomi_Lev,1) <= #{kkomiLev} and NVL(tk.kkomi_Exp,0) <= #{kkomiExp} ;
